export interface PresetAssert {
    isTrue: (value: any) => void;
    isFalse: (value: any) => void;
    isTruly: (value: any) => void;
    isFalsy: (value: any) => void;
    isBoolean: (value: any) => void;
    isFunction: (value: any) => void;
    isArray: (value: any) => void;
    isNull: (value: any) => void;
    isUndefined: (value: any) => void;
    isNumber: (value: any) => void;
    isObject: (value: any) => void;
    isString: (value: any) => void;
    isEqual: (value1: any, value2: any) => void;
    isBe: (value1: any, value2: any) => void;
    isLength: (value: any, min: number, max: number) => void;
    isMatch: (value: any, regexp: RegExp) => void;
    isBelong: (value: any, list: Array<any>) => void;
    isError: (error: (() => unknown) | Error) => void;
}
